def source(
    source_id: str,
    jurisdiction: str,
    agency: str,
    native_name: str,
    english_name: str,
    product_type: str,
    flood_types: list[str],
    scenarios: list[str],
    coverage: str,
    formats: list[str],
    license_name: str | None,
    delivery_mode: str,
    primary: str | None,
    *,
    service: str | None = None,
    download: str | None = None,
    resolution_scale: str | None = None,
    access_constraints: list[str] | None = None,
    is_fallback: bool = False,
    is_material: bool = True,
    notes: str = "",
) -> dict[str, Any]:
    return {
        "id": source_id,
        "jurisdiction": jurisdiction,
        "agency": agency,
        "native_name": native_name,
        "english_name": english_name,
        "product_type": product_type,
        "flood_types": flood_types,
        "scenarios": scenarios,
        "coverage": coverage,
        "resolution_scale": resolution_scale,
        "formats": formats,
        "license": license_name,
        "delivery_mode": delivery_mode,
        "access_constraints": access_constraints or [],
        "links": {"primary": primary, "service": service, "download": download},
        "last_update": None,
        "is_fallback": is_fallback,
        "is_material": is_material,
        "supersedes_id": None,
        "verification": {
            "status": "unverified",
            "http_status": None,
            "content_type": None,
            "final_url": None,
            "evidence": None,
            "checked_at": None,
            "checked_by": None,
        },
        "provenance": {"produced_by": "codex", "round": 1},
        "notes": notes,
    }


def region(
    rank: int,
    name: str,
    population: int,
    pop_year: int,
    pop_source: str,
    pop_source_url: str,
) -> dict[str, Any]:
    return {
        "rank": rank,
        "name": name,
        "population": population,
        "pop_year": pop_year,
        "pop_source": pop_source,
        "pop_source_url": pop_source_url,
    }


