def build_country(iso2: str) -> dict[str, Any]:
    spec = CATALOG[iso2]
    searches, page_reads, probes, stop_reason = spec["metrics"]
    artifact = {
        "artifact_type": "country",
        "schema_version": SCHEMA_VERSION,
        "report_scope": "final",
        "iso2": iso2,
        "country_name": spec["country_name"],
        "coverage_model": spec["coverage_model"],
        "fragmentation_summary": spec["fragmentation_summary"],
        "top_regions": spec["top_regions"],
        "deferred_regions": spec["deferred_regions"],
        "score": None,
        "confidence": None,
        "score_provisional": bool(spec["deferred_regions"]),
        "subscores": None,
        "sources": spec["sources"],
        "discovery_metrics": {
            "searches": searches,
            "page_reads": page_reads,
            "capability_probes": probes,
            "consecutive_empty_searches": 0,
            "stop_reason": stop_reason,
        },
        "provenance": {"discovered_by": "codex", "discovered_at": utc_now()},
    }
    validate_artifact(artifact)
    return artifact


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("iso2", choices=sorted(CATALOG))
    args = parser.parse_args()
    artifact = build_country(args.iso2)
    destination = DATA_DIR / f"{args.iso2}.json"
    atomic_write_json(destination, artifact)
    print(f"wrote {destination} with {len(artifact['sources'])} unverified candidates")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
